VALUES
  ('heelevel3-988e0de1-moex-00059', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何者最不可能是關鍵查核事項？', '["重大匯兌損失", "導致會計師出具修正式意見之事項", "使受查者繼續經營能力具不確定性之事項", "重大非常規關係人交易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00060', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '審計準則700號（原審計準則公報第五十七號）「財務報表查核報告」就會計師對財務報表形成查 核意見之責任，以及其依查核結果所出具查核報告之格式及內容等均有規範。下列敘述何者錯誤？', '["查核報告應依案件之情況載明報告收受者", "於執行集團查核時，如涉及不同會計師職業道德規範，查核報告中通常提及集團查核團隊所適 用之會計師職業道德規範", "對適用之財務報導架構之說明，若包括不精確之描述或限制性文字（例如「財務報表大致遵循 XX準則」），則可能誤導財務報表使用者，因此非屬適當", "會計師對依照遵循架構編製之財務報表出具無保留意見之查核報告時，查核意見應敘明「依本 會計師之意見，上開財務報表在所有重大方面係依照[適用之財務報導架構]編製，足以允當表 達……」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00061', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列那種情況會計師應出具無法表示意見之查核報告？', '["受查公司呆帳少估3億元，嚴重影響財務報表之允當表達", "受查公司帳冊遭火災焚毀，會計師執行其他替代查核程序亦無法取得足夠及適切之查核證據", "受查公司未揭露金額重大的法律訴訟案", "已決定清算之受查公司仍然用繼續經營之會計基礎編製財務報表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00062', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列有關會計師事務所為審計客戶提供非審計業務，何者不會影響獨立性？①依審計準則，為財', '["事務所關係企業提供審計客戶評價服務，且評價 結果將形成財務報表之一部分", "事務所派遣內部員工，協助審計客戶執行工作", "協助審計客 戶處理與稅捐機關之爭議", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00063', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '執行元額單位抽樣（MonetaryUnitSampling）時，若某一客戶的應收帳款帳載金額為$45,000，查 核後金額為$30,000，而抽樣間距為$30,000，預期錯誤金額為多少？', '["$10,000", "$15,000", "$20,000", "$30,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00064', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '偵查舞弊的技巧及建立反舞弊程序與內部控制制度，大都基於舞弊三角（FraudTriangle）理論。 下列何者不是舞弊三角的要素？', '["心理狀態", "機會", "誘因及壓力", "態度或合理化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00065', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '關於舞弊預防程序和控制制度建立，下列敘述何者錯誤？', '["管理階層應負擔其建立舞弊預防程序和控制制度的主要責任", "公司法務人員應負責執行反舞弊程序和控制活動", "上市或上櫃公司的審計委員會是公司最高反舞弊的監督機構，應該擔負監督的責任", "會計師及查核人員主要責任，在辨識反舞弊機制是否有效降低因舞弊所產生的重大不實表達風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00066', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員於受查者存在關係人交易情況下之偵出重大不實表達的能力，受先天限制之潛在影響較 大，下列何者並非主要原因？', '["該類關係人交易金額並不重大", "管理階層可能未知悉所有關係人之關係及交易之存在", "關係人交易通常透過複雜結構的安排下進行", "關係人之關係可能給予管理階層共謀、隱匿及操縱之更佳機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00067', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關「分析性程序」，下列敘述何者正確？', '["查核人員可利用分析性程序，經考量租金、公寓數量及空屋率後，推估出租公寓之總租金收入", "銷貨訂單處理流程之控制若存有缺失，則關於應收帳款之聲明，查核人員可能較依賴證實分析 性程序，而非細項測試", "取得與應收帳款餘額之評價聲明有關之查核證據時，查核人員僅對帳齡執行分析性程序，以判 斷應收帳款之收現性即可完成", "分析性程序可考量財務資訊與攸關非財務資訊間之關係，例如最近3年之銷貨毛利率計算與比較"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00068', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-111-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依據審計準則510號（原審計準則公報第六十三號）「首次受託查核案件－期初餘額」之規定， 有關查核人員首次受託查核時，下列對期初餘額之查核對當期查核報告之影響敘述何者錯誤？', '["如查核人員無法對存貨之期初餘額取得足夠及適切之查核證據，會計師可能出具對綜合損益 表、權益變動表及現金流量表表示保留意見或無法表示意見，而對資產負債表表示無保留意見 之查核報告", "會計師如作出期初餘額所適用之會計政策未依適用之財務報導架構於本期一致適用之結論時， 則應表示保留意見或無法表示意見", "會計師如推斷期初餘額存有重大影響本期財務報表之不實表達，且其影響未適當處理、表達或 揭露，則應表示保留意見或否定意見", "如前任會計師對前期財務報表表示修正式意見，且導致修正式意見之事項對本期財務報表仍屬 攸關且重大，繼任會計師應對本期財務報表表示修正式意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
